import be.schaubroeck.lpb.rkm.rekenmotor.bv.BvTools;
import be.schaubroeck.lpb.rkm.rekenmotor.comparator.RekenHoofdByFiscaalJaarComparator;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.ContextKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.MoneyKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.HashMoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeManagerImp;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManagerImp;
import be.schaubroeck.lpb.rkm.rekenmotor.util.MoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PersoonsDataManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.PersoonsFiscaliteit;
import be.schaubroeck.lpb.tools.RekenBedrag;
import be.schaubroeck.lpb.tools.RekenHoofd;
import be.schaubroeck.lpb.tools.RekenInfo;
import be.schaubroeck.lpb.tools.RekenLijn;
import be.schaubroeck.lpb.tools.caching.ake.AardKodeExtensieFacade;
import be.schaubroeck.lpb.tools.enumtypes.LnedefRegBv;
import be.schaubroeck.lpb.tools.enumtypes.RekenBedragType;
import be.schaubroeck.lpb.tools.enumtypes.VrbrwWrkwBv;
import be.schaubroeck.lpb.tools.util.AlgemeenTools;
import org.joda.time.LocalDate;

import java.util.HashMap;
import java.util.HashSet;
import java.util.List;
import java.util.Map;
import java.util.Map.Entry;
import java.util.Set;
import java.util.SortedSet;

import static be.schaubroeck.lpb.rkm.rekenmotor.LooncodeGroepKeyStrings.BESLAG_OP_LOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.AFWIJKEND_REGIME_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.FISCAAL_JAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PRE_BEREKENING_CONTEXT_KEY;

public class PreBerekeningInterpreterImp implements PreBerekeningInterpreter {

    private AardKodeExtensieFacade aardKodeExtensieFacade;

    public PreBerekeningInterpreterImp(AardKodeExtensieFacade aardKodeExtensieFacade) {
        this.aardKodeExtensieFacade = aardKodeExtensieFacade;
    }

    @Override
    public RekenContext vormPreBerekeningContext(Persoon persoon, PersoonsDataManager dataManager, RekenTijd rekenTijd, RegulManager regulManager) {
        Persoon persoonKwartaalSimpel = dataManager.getPersoonKwartaalSimpel();
        boolean heeftOpdrachtBedrijfsvoorheffingVrijwilligeBrandweer = RekenTools.heeftOpdrachtBedrijfsvoorheffingVrijwilligeBrandweer(persoonKwartaalSimpel);
        LoonCodeManager loonCodeManager = new LoonCodeManagerImp(regulManager, aardKodeExtensieFacade);
        RekenContext preBerekeningContext = new RekenContext();
        preBerekeningContext.put(PERSOON_KEY, persoon);
        preBerekeningContext.put(LOONELEMENT_MANAGER_KEY, new LoonElementManagerImp());

        //Root node nodig voor sommige edge-cases (i.e. geen resultaten uit een vorig fiscaal jaar)
        RekenContext empty = copyPreBerekeningContext(preBerekeningContext);
        preBerekeningContext.put(PRE_BEREKENING_CONTEXT_KEY, empty);
        preBerekeningContext.put(FISCAAL_JAAR_KEY, 0);

        Map<Integer, AardKodeExtensie> akeIdToAardKodeExtensieMap = new HashMap<>();

        Map<Integer, Opdracht> idToOpdracht = AlgemeenTools.maakIdToIdentifiableMap(persoon.getOpdrachten());

        List<RekenHoofd> bestaanden = dataManager.getBestaandeRekenResultaten(rekenTijd.beginDatum);
        SortedSet<RekenHoofd> sorted = RekenHoofdByFiscaalJaarComparator.createSortedSet(bestaanden);

        Sommaties sommatiesCommand = new Sommaties();
        SommatiesAchterstal sommatiesAchterstal = new SommatiesAchterstal();
        Integer currFiscaalJaar = 0;
        if (!sorted.isEmpty()) {
            currFiscaalJaar = sorted.iterator().next().getFiscaalJaar();
        }
        for (RekenHoofd hoofd : sorted) {
            if (!(currFiscaalJaar.equals(hoofd.getFiscaalJaar()))) {
                RekenContext copy = copyPreBerekeningContext(preBerekeningContext);
                copy.put(PRE_BEREKENING_CONTEXT_KEY, preBerekeningContext);

                preBerekeningContext.put(FISCAAL_JAAR_KEY, currFiscaalJaar);
                sommatiesCommand.execute(preBerekeningContext);
                sommatiesAchterstal.execute(preBerekeningContext);

                preBerekeningContext = copy;
                currFiscaalJaar = hoofd.getFiscaalJaar();
            }
            if (hoofd.getRnummer() != null) {
                Opdracht opdracht = idToOpdracht.get(hoofd.getOpdracht().getId());
                LoonElementManager loonElementManager = preBerekeningContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
                for (RekenLijn lijn : hoofd.getRekenLijnen()) {
                    Opper opper = RekenTools.findOpper(opdracht, lijn.getEindDatum());
                    if (opper == null) {
                        opper = RekenTools.getOpperLaatsteGegevens(opdracht);
                    }

                    AardKodeExtensie looncode = akeIdToAardKodeExtensieMap.get(lijn.getAardKodeExtensie().getId());
                    if (looncode == null) {
                        looncode = loonCodeManager.getById(lijn.getAardKodeExtensie().getId());
                        akeIdToAardKodeExtensieMap.put(looncode.getId(), looncode);
                    }

                    LocalDate beslagDatum = null;
                    if (looncode.behoortTotGroep(BESLAG_OP_LOON_KEY)) {
                        beslagDatum = hoofd.getBeslagDatum();
                    }

                    LoonElement element = loonElementManager.getLoonElement(looncode, opper, beslagDatum, lijn.getReferentieJaar());
                    if (element == null) {
                        element = new LoonElement(looncode);
                        element.setReferentieJaar(lijn.getReferentieJaar());
                        element.setBeslagDatum(beslagDatum);
                        if (lijn.getRegimeBv() != looncode.getRegimeBv() && !checkEnkelRekenBedragenMetAfwijkendRegime(lijn.getRekenBedragen())) {
                            element.putProperty(RekenChainKey.AFWIJKEND_REGIME_KEY, lijn.getRegimeBv());
                        }
                        loonElementManager.addLoonElement(element, opper);
                    }

                    PersoonsFiscaliteit persoonsFiscaliteit = dataManager.getPersoonsFiscaliteitOpStartFiscaalJaar();
                    VrbrwWrkwBv fiscaleWerkwijze = null;
                    if (persoonsFiscaliteit != null) {
                        fiscaleWerkwijze = persoonsFiscaliteit.getWerkwijzeVrijwilligeBrandweer();
                    }
                    boolean gebruikBvVrwBrw = heeftOpdrachtBedrijfsvoorheffingVrijwilligeBrandweer && fiscaleWerkwijze != VrbrwWrkwBv.BAREMA_GFV
                            && fiscaleWerkwijze != VrbrwWrkwBv.PERCENTAGE_GFV;
                    for (RekenBedrag bedrag : lijn.getRekenBedragen()) {
                        LnedefRegBv regime = lijn.getRegimeBv();
                        if (gebruikBvVrwBrw && bedrag.getBedragType() == RekenBedragType.BEDRIJFSVOORHEFFING && BvTools.BV_VRIJWILLIGE_BRANDWEER_CHECKER.check(element)) {
                            regime = LnedefRegBv.VD_BV_10_BZ___VB;
                        }
                        MoneyKey moneyKey = RekenTools.bedragTypeToMoneyKey(bedrag.getBedragType(), regime, hoofd.getBeginDatum());
                        element.addToProperty(moneyKey, bedrag.getBedrag());
                    }
                    for (RekenInfo info : lijn.getRekenInfos()) {
                        element.putProperty(RekenTools.infoTypeToRekenInfoKey(info.getInfoType()), info.getInfo());
                    }
                }
                for (LoonElement element : loonElementManager.getPersoonsElementen()) {
                    MoneyKey moneyKey =
                            RekenTools.bedragTypeToMoneyKey(RekenBedragType.BEDRIJFSVOORHEFFING, element.getAardKodeExtensie().getRegimeBv(), hoofd.getBeginDatum());
                    if (element.getProperty(AFWIJKEND_REGIME_KEY) != null && element.getPropertyMoney(moneyKey).signum() != 0) {
                        element.getProperties().remove(AFWIJKEND_REGIME_KEY);
                    }
                    MoneyMap<RekenBvKey> checkBvMatchRegimeMap = new HashMoneyMap<>();
                    Set<ContextKey> removeKeys = new HashSet<>();
                    for (ContextKey key : element.getProperties().keySet()) {
                        if (key instanceof MoneyKey && element.getPropertyMoney(key).signum() == 0) {
                            removeKeys.add(key);
                        }
                        if (key instanceof RekenBvKey) {
                            checkBvMatchRegimeMap.addToMoney((RekenBvKey) key, element.getPropertyMoney(key));
                        }
                    }
                    MoneyKey expectedKey =
                            RekenTools.bedragTypeToMoneyKey(RekenBedragType.BEDRIJFSVOORHEFFING, element.getRegimeBv(), hoofd.getBeginDatum());
                    if (checkBvMatchRegimeMap.size() == 1 && expectedKey != checkBvMatchRegimeMap.keySet().iterator().next()) {
                        RekenBvKey bvKey = checkBvMatchRegimeMap.keySet().iterator().next();
                        LnedefRegBv bvRegime = BvTools.bvKeyToRegime(bvKey);
                        if (expectedKey != bvKey && bvRegime != null && bvKey.toEnumType() == RekenBedragType.BEDRIJFSVOORHEFFING) {
                            element.putProperty(AFWIJKEND_REGIME_KEY, bvRegime);
                        }
                    }

                    for (ContextKey key : removeKeys) {
                        element.getProperties().remove(key);
                    }

                }
            }

        }

        sommatiesCommand.execute(preBerekeningContext);
        sommatiesAchterstal.execute(preBerekeningContext);
        preBerekeningContext.put(FISCAAL_JAAR_KEY, currFiscaalJaar);
        return preBerekeningContext;
    }

    private boolean checkEnkelRekenBedragenMetAfwijkendRegime(Set<RekenBedrag> rekenBedragen) {
        boolean checked = true;
        for (RekenBedrag rekenBedrag : rekenBedragen) {
            checked = checked && rekenBedrag.getBedragType() == RekenBedragType.VERMINDERING_BEDRIJFSVOORHEFFING_INHOUDINGEN;
        }
        return checked;
    }

    private RekenContext copyPreBerekeningContext(RekenContext master) {
        RekenContext copy = new RekenContext();
        Persoon persoon = master.getUnchecked(PERSOON_KEY);
        copy.put(PERSOON_KEY, persoon);
        LoonElementManagerImp loonElementManager = new LoonElementManagerImp();
        copy.put(LOONELEMENT_MANAGER_KEY, loonElementManager);
        LoonElementManagerImp masterLoonElementManager = master.getUnchecked(LOONELEMENT_MANAGER_KEY);
        for (LoonElement element : masterLoonElementManager.getPersoonsElementen()) {
            LoonElement copyElement = new LoonElement(element.getAardKodeExtensie());
            copyElement.setBeslagDatum(element.getBeslagDatum());
            copyElement.setReferentieJaar(element.getReferentieJaar());
            for (Entry<ContextKey, Object> entry : element.getProperties().entrySet()) {
                copyElement.putProperty(entry.getKey(), entry.getValue());
            }
            loonElementManager.addLoonElement(copyElement, element.getOpper());
        }
        return copy;
    }
}
